(102, 146, 30, 18, 8.00, 20, '2026-02-26 02:36:11', '{\"1061\":\"DISMISSAL, LAST\",\"1062\":\"DISCIPLINARY ACTION, INVESTIGATION\",\"1063\":\"CHANCE, DUE PROCESS\",\"1064\":\"CODE OF CONDUCT, REGARDLESS\",\"1060\":\"PUNITIVE, CORRECTIVE\",\"1065\":\"MALI\\r\\nHindi maaring i-terminate ni Manager ang isang staff, kailangan niya itong i report sa HR dahil meron itong due process. \",\"1066\":\"MALI\\r\\nKailangan niya muna mag report sa HR dahil may nalabag siyang polisiya. \"}', 0, NULL),
(103, 146, 25, 13, 6.00, 20, '2026-02-26 02:38:37', '{\"1060\":\"Punitive, Corrective\",\"1064\":\"Code of Conduct, Regardless\",\"1061\":\"Disciplinary Action, Last\",\"1062\":\"Dismissal, Investigation \",\"1063\":\"Chance, Reminder\",\"1066\":\"MALI, kailangan muna nyang mag report sa HR, dahil kungb may sakit sya kailangan nya pa din mag report sa branch\",\"1065\":\"MALI, dadaan muna ito sa HR, at sila po ang mag bibigay kung anu ang dapat na parusa sa staff\"}', 0, NULL),
(104, 146, 38, 17, 8.00, 20, '2026-02-26 02:38:38', '{\"1063\":\"CHANCE,INVESTIGATION\",\"1062\":\"DISCIPLINARY ACTION,INVESTIGATION\",\"1064\":\"CODE OF CONDUCT,REGARDLESS\",\"1060\":\"PUNITIVE,CORRECTIVE\",\"1061\":\"DISMISSAL,LAST\",\"1066\":\"Mali-dahil kailangan muna itong ireport sa hr at dadaan sa due process dahil may nilabag siyang policy\",\"1065\":\"Mali-dahil kailangan niya munang magsubmit ng deliquency report sa hr,at dadaan sa due process at si hr at magcoconduct ng investigation\"}', 0, NULL),
(105, 146, 28, 20, 10.00, 20, '2026-02-26 02:38:48', '{\"1064\":\"Code of Conduct, Regardless\",\"1063\":\"Chance, Due Process\",\"1061\":\"Dismissal, Last\",\"1062\":\"Disciplinary Action, Investigation\",\"1060\":\"Punitive, Corrective\",\"1066\":\"MALI- Dahil una walang pong paalam ang staff. Dapat e report po sa hr, and need po e verify yung medical certificate na pinasa ng staff.\",\"1065\":\"MALI- dahil pagdating sa pag terminate ng tao o staff may due process po tayong sinusunod at dapat po documented and reported po ito sa hr.\"}', 0, NULL),
(106, 146, 31, 16, 8.00, 20, '2026-02-26 02:39:41', '{\"1064\":\"Code of conduct , regardles\",\"1062\":\"  Disciplinary action  ,       Investigation\",\"1063\":\"Sinumpaang salaysay, due process\",\"1060\":\"Punitive , corrective\",\"1061\":\"Dismissal, last\",\"1066\":\"Mali,\\r\\nKailangan po mag report muna sa HR yung isang staff, dahil may nilabag siya na policy, dahil may sinusunod po tayo na due process . \",\"1065\":\"MALI\\r\\nHindi po maaring mag terminate ang isang manager , ang tamang gawin ni manager  ay mag report sa HR kalakip po yung mga documents  para mabasa po ni HR ,  at kailan natin sundin ang dues process about this matter.\"}', 0, NULL),
(107, 146, 27, 18, 8.00, 20, '2026-02-26 02:39:51', '{\"1060\":\"Punitive, Corrective \",\"1064\":\"Code of conduct, Regardless \",\"1061\":\"Dismissal, Last\",\"1062\":\"Disciplinary action, Investigation\",\"1063\":\"Chance, Due process \",\"1066\":\"MALI - ito ay kailangang ireport kay HR dahil siya ay may nailabag sa policy at siya ay kailangang mag report sa HR para magpaliwanag. \",\"1065\":\"MALI - Hindi maaring mag Terminate si manager dahil ito ay kailangang ireport sa HR kalakip neto ang mga dokyumento na angkop sa kaso, dahil ito ay kailangang dumaan muna sa tinatawag na Due process. \"}', 0, NULL),
(108, 146, 32, 18, 8.00, 20, '2026-02-26 02:39:57', '{\"1063\":\"CHANCE, DUE PROCESS\",\"1061\":\"Dismissal, last\",\"1060\":\"Punitive, corrective\",\"1062\":\"Disciplinary action, investigation\",\"1064\":\"Code of conduct, regardless\",\"1066\":\"MALI\\r\\n\\r\\nMali as a manager we need to verify the medical certificate of our staff and report to HR department upang masunod ang due process at ang HR ang mag dedecide ng violation ng ating staff using our company policy.\",\"1065\":\"MALI\\r\\n\\r\\nhindi po maaring mag terminate ang manager ng staff kahit ito pa ay may nagawang kasalanan na katumbas ng class D, maaari lamang gawin ng manager ay i report sa HR upang ang ma investigate at ang HR ang mag bibigay ng last decision kung anu ang naging violation ng isang empleyado at nauukol sa ating company policy. \"}', 0, NULL),
(109, 146, 36, 20, 10.00, 20, '2026-02-26 02:41:17', '{\"1062\":\"Disciplinary Action, Investigation \",\"1064\":\"Code of Conduct , Regardless \",\"1063\":\"Chance, Due Process\",\"1061\":\"Dismissal, Last\",\"1060\":\"Punitive, Corrective \",\"1065\":\"MALI\\r\\n\\r\\nNeed to report the incident to HR for thorough investigation about the incident and give the staff a chance for his side as part of the due process, also give your incident report as part of the documentation and let the HR decide and how should it be done in proper way.\",\"1066\":\"MALI\\r\\n\\r\\nFirst, validated the given MedCert as part of your investigation and let the HR be informed about the absences without official leave that the staff committed, and also wait the HR decisions for the sanctions\\/penalty.\"}', 0, NULL),
(110, 146, 26, 20, 10.00, 20, '2026-02-26 02:41:25', '{\"1060\":\"Punitive,Corrective\",\"1063\":\"Chance, Due Process\",\"1064\":\"Code of Conduct, Regardless\",\"1061\":\"Dismissal,Last\",\"1062\":\"Disciplinary Action, Investigation\",\"1065\":\"MALI\\r\\nStore managers are not allowed to terminate staff. If a staff committed a class D offense, the manager must report this to HR department for proper investigation as part of due process, then only them will give appropriate sanction to the employee.\",\"1066\":\"MALI\\r\\n4 to 5 days of not reporting to work with no authorization or proper communication will be considered as AWOL. Since the staff provided medical certificate, this should be reported to HR department for investigation as part of due process then wait for futher instructions from them. \"}', 0, NULL),
(111, 146, 33, 20, 10.00, 20, '2026-02-26 02:41:50', '{\"1062\":\"Disciplinary action , Investigation \",\"1060\":\"Punitive , Corrective \",\"1061\":\"Dismissal , last\",\"1063\":\"Chance, Due process\",\"1064\":\"Code of conduct, regardless\",\"1065\":\"Mali ,\\r\\nAng store manager ay hindi maaring mag terminate ng staff, kailangan ipasa ang DR at iba pang documents tungkol sa violation sa HR department ng staff para dumaan sa due process violation na nagawa ng staff\",\"1066\":\"Mali,\\r\\nDapat ang staff ay mag report muna sa HR department dahil violation Nia sa policy dadaan muna sa due process ang kanyang violation na Absent without official leave\"}', 0, NULL),
(112, 146, 34, 17, 10.00, 20, '2026-02-26 02:41:59', '{\"1062\":\"Code of conduct ,Investigation \",\"1061\":\"Dismissal, Last\",\"1063\":\"DUE PROCESS, SINUMPAANG SALAYSAY\",\"1064\":\"Code of conduct, Regardless \",\"1060\":\"Punitive, Corrective\",\"1066\":\"Mali po una sa lahat my nalabag na po ang staff sa code of conduct kailangan po mag report ng staff sa HR muna and c HR po ang mag advice ky manager if ito ay bibigyan pa ng scedule.\",\"1065\":\"Mali dahil kailangan po muna dumaan ng  due process ang nagawa ng staff at si HR po ang mag bibigay ng termination or hatol  not si manager.\"}', 0, NULL),
(113, 146, 37, 20, 10.00, 20, '2026-02-26 02:43:16', '{\"1062\":\"Disciplinary Action, Investigation \",\"1064\":\"Code of conduct, Regardless \",\"1060\":\"Punitive, Corrective \",\"1061\":\"Dismissal, Last\",\"1063\":\"Chance, Due process \",\"1065\":\"MALI- Kailangan ireport natin sa HR ang staff kung siya ay nakagawa ng mabigat na kasalanan at meron parin due process na sinusunod at si HR ang mag bibigay ng Disciplinary action.\",\"1066\":\"MALI- Kailangan ireport natin sa HR ang staff at kailangan din natin iverify ang medical certificate sa hospital or clinic kung legit ba ito. \"}', 0, NULL),
(114, 146, 35, 18, 8.00, 20, '2026-02-26 02:44:31', '{\"1064\":\"CODE OF CONDUCT, REGARDLESS \",\"1063\":\"CHANCE, DUE PROCESS\",\"1062\":\"DISCIPLINARY ACTION, INVESTIGATION \",\"1060\":\"PUNITIVE, CORRECTIVE \",\"1061\":\"DISMISSAL, LAST\",\"1066\":\"MALI - sa pagkat Ang 4-5 days ay nabibilang sa CLass D and 3 consecutive days na considered as AWOL most probably, need nya po mag report Kay HR. Para po sila Ang mag decide ng Notice of Decision and Disciplinary action. \",\"1065\":\"Mali- Sa pagkat ang pag teterminate ay may tamang paghatol na naka angkop sa company code of code na Ang HR po dapat Ang mag decide Hindi po manager dahil Ito po ay may due process. \"}', 0, NULL),
(115, 146, 39, 18, 8.00, 20, '2026-02-26 02:44:37', '{\"1061\":\"dismissal, last\",\"1060\":\"punitive, corrective \",\"1062\":\"disciplinary action,  investigation \",\"1063\":\"chance, due process\",\"1064\":\"code of conduct, regardless\",\"1065\":\"MALI - hindi maari na magtangal ang manager dahil may sinusunod tayong \\\"due process\\\" ang gagawin po ay ireport sa HR na my mga kalakip na documents. \",\"1066\":\"MALI - hindi na maaring tanggapin dahil may nilabag siya sa \\\"code of conduct\\\" siya po ay mapupuntahin ko sa hr para magreport po doon. \"}', 0, NULL),
