(955, 143, 'Basic duties of a Service Crew: 1) Clean and prepare, 2) Serve and assist, & 3) Inventory, Reports, and endorse', 'Write the word TRUE if the statement is correct and FALSE if the statement is incorrect.', 'True/False', 1, '', '', '', '', 'TRUE'),
(956, 143, 'DR7 Four Seasons’ standard ingredients is 100g Pineapple tidbits, 1 pack mango puree, 1/2 jigger of Guyabano Extract, 1/2 jigger calamansi extract, 1/2 jigger of sugar syrup, 1/2 jigger of grenadine syrup and 8 oz of crushed ice', 'Write the word TRUE if the statement is correct and FALSE if the statement is incorrect.', 'True/False', 1, '', '', '', '', 'FALSE'),
(957, 143, 'Standard preparation of DR1 Chrysanthemum drinks is Put 50 grams of Chrysanthemum powder in 16 oz cambro  glass, 5 cubes of ice and add 12 oz of Purified water shake to ensure granules are completely diluted.', 'Write the word TRUE if the statement is correct and FALSE if the statement is incorrect.', 'True/False', 1, '', '', '', '', 'TRUE'),
(958, 143, 'Basic duties of a Kitchen Staff 1) Clean and prepare, 2) Serve and assist, & 3) Inventory, Report, and Endorse', 'Write the word TRUE if the statement is correct and FALSE if the statement is incorrect.', 'True/False', 1, '', '', '', '', 'TRUE'),
(959, 143, 'To check for possible gas leak, we use the sensory evaluation test on the gas cylinder tank and gas connection pipe', 'Write the word TRUE if the statement is correct and FALSE if the statement is incorrect.', 'True/False', 1, '', '', '', '', 'FALSE'),
