(961, 143, 'The safe holding time for steamed rice in a rice warmer is 6 hours.', 'Write the word TRUE if the statement is correct and FALSE if the statement is incorrect.', 'True/False', 1, '', '', '', '', 'TRUE'),
(962, 143, 'In the absence of the Store Admin Assistant during sales pick-up, the Store Manager or the Assistant Store Manager can take their place.', 'Write the word TRUE if the statement is correct and FALSE if the statement is incorrect.', 'True/False', 1, '', '', '', '', 'TRUE'),
(963, 143, 'MEMC stands for Most Expensive Meal Cost.', 'Write the word TRUE if the statement is correct and FALSE if the statement is incorrect.', 'True/False', 1, '', '', '', '', 'FALSE'),
