(965, 143, 'For guests with dietary restriction on pork and wants to eat Noodles in Soup, we can use Chicken stock soup base.', 'Write the word TRUE if the statement is correct and FALSE if the statement is incorrect.', 'True/False', 1, '', '', '', '', 'TRUE'),
(966, 143, 'We can offer GRC to dine-in customers as long as they meet the minimum order of 10.', 'Write the word TRUE if the statement is correct and FALSE if the statement is incorrect.', 'True/False', 1, '', '', '', '', 'FALSE'),
