(970, 143, 'Who is responsible for ensuring that the pre-opening and closing schedules are followed?', 'Read the questions carefully and encircle the correct answer.', 'MCQ', 1, 'Security Guard', 'Cashier', 'On-duty Manager', 'Kitchen Supervisor', 'On-duty Manager'),
(971, 143, 'What is the first step in the store pre-opening procedure?', 'Read the questions carefully and encircle the correct answer.', 'MCQ', 1, 'Open POS system', 'Conduct staff briefing', 'Log time of arrival in employee log sheet', 'Read endorsement logbook', 'Log time of arrival in employee log sheet'),
(972, 143, 'What should be done if there are issues with the POS system before opening?', 'Read the questions carefully and encircle the correct answer.', 'MCQ', 1, 'Ask approval from Area Manager', 'Report to MIS Department', 'Call PLDT and get ticket number', 'Ask the cashier to fix it', 'Report to MIS Department'),
